import { alpha, Checkbox, Container, FormControlLabel, Grid, InputBase, makeStyles, Paper, Table, TableBody, TableCell, TableContainer, TableHead, TableRow, Toolbar, Typography } from '@material-ui/core'
import { Search } from '@material-ui/icons';
import React, { useEffect, useState } from 'react'
import axios from 'axios'

const useStyle = makeStyles(theme => {
  return {
    tableHead: {
      backgroundColor: 'rgba(128, 128, 128, 0.527)',
    },
    title: {
      marginTop: '7px'
    },
    search: {
      position: 'relative',
      borderRadius: theme.shape.borderRadius,
      backgroundColor: alpha(theme.palette.common.white, 0.15),
      '&:hover': {
        backgroundColor: alpha(theme.palette.common.white, 0.25),
      },
      marginRight: theme.spacing(2),
      marginLeft: 0,
      width: '100%',
      [theme.breakpoints.up('sm')]: {
        marginLeft: theme.spacing(3),
        width: 'auto',
      },
    },
    searchIcon: {
      padding: theme.spacing(0, 2),
      height: '100%',
      position: 'absolute',
      pointerEvents: 'none',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
    },
    inputRoot: {
      color: 'inherit',
    },
    inputInput: {
      padding: theme.spacing(1, 1, 1, 0),
      // vertical padding + font size from searchIcon
      paddingLeft: `calc(1em + ${theme.spacing(4)}px)`,
      transition: theme.transitions.create('width'),
      width: '100%',
      [theme.breakpoints.up('md')]: {
        width: '20ch',
      },
    },
  }
})

export default function Admin() {
  const classes = useStyle();

  useEffect(() => {
    showStudents();
    showInstructors();
    showClassrooms();
  }, []);

  const [students, setStudents] = useState([]);

  function showStudents() {
    axios.get('http://localhost:80/api/getStudents.php')
      .then((response) => {
        setStudents(response.data);
        if (response.data.Status == 'Invalid') {
          alert('Invalid User');
        } else {
          // navigate('/teacherDashboard')
        }
      })
  };

  const [instructors, setInstructors] = useState([]);
  function showInstructors() {
    axios.get('http://localhost:80/api/getInstructors.php')
      .then((response) => {
        setInstructors(response.data);
        if (response.data.Status == 'Invalid') {
          alert('Invalid User');
        } else {
          // navigate('/teacherDashboard')
        }
      })
  }

  const [classrooms, setClassrooms] = useState([]);
  function showClassrooms() {
    axios.get('http://localhost:80/api/getClassrooms.php')
      .then((response) => {
        setClassrooms(response.data);
        if (response.data.Status == 'Invalid') {
          alert('Invalid User');
        } else {
          // navigate('/teacherDashboard')
        }
      })
  }


  return (
    <>
      <Container>
        <Grid container spacing={10}>


          {/* ADMIN */}
          <Grid item xs={12}>
            <section>
              <Container>
                <Paper elevation={7}>
                  <TableContainer>
                    <Toolbar>
                      <Typography className={classes.title} variant="h6" noWrap>
                        Admins
                      </Typography>
                      <div className={classes.search}>
                        <div className={classes.searchIcon}>
                          <SearchIcon />
                        </div>
                        <InputBase
                          placeholder="Search…"
                          classes={{
                            root: classes.inputRoot,
                            input: classes.inputInput,
                          }}
                          inputProps={{ 'aria-label': 'search' }}
                        />
                      </div>
                    </Toolbar>
                    <Table>
                      <TableHead className={classes.tableHead}>
                        <TableRow>
                          <TableCell padding='checkbox'>
                            <Checkbox />
                          </TableCell>
                          <TableCell>ID</TableCell>
                          <TableCell>Student ID</TableCell>
                          <TableCell>Name</TableCell>
                          <TableCell>Password</TableCell>
                        </TableRow>
                      </TableHead>
                      <TableBody>
                        <TableRow>
                          <TableCell padding='checkbox'>
                            <Checkbox />
                          </TableCell>
                          <TableCell>1</TableCell>
                          <TableCell>101190604</TableCell>
                          <TableCell>Cris Philip V. Cajurao</TableCell>
                          <TableCell>test1</TableCell>
                        </TableRow>
                      </TableBody>
                    </Table>
                  </TableContainer>
                </Paper>
              </Container>
            </section>
          </Grid>


          {/* STUDENTS LIST */}
          <Grid item xs={12}>
            <section>
              <Container>
                <Paper elevation={7}>
                  <TableContainer>
                    <Container>
                      <Typography className={classes.title} variant='h4'>
                        Student List
                      </Typography>
                    </Container>
                    <Toolbar>
                      <div className={classes.searchIcon}>
                        <Search />
                      </div>
                      <InputBase
                        placeholder="Search…"
                        classes={{
                          root: classes.inputRoot,
                          input: classes.inputInput,
                        }}
                        inputProps={{ 'aria-label': 'search' }}
                      />
                    </Toolbar>
                    <Table>
                      <TableHead className={classes.tableHead}>
                        <TableRow>
                          <TableCell padding='checkbox'>
                            <Checkbox />
                          </TableCell>
                          <TableCell>ID</TableCell>
                          <TableCell>Student ID</TableCell>
                          <TableCell>Name</TableCell>
                          <TableCell>Password</TableCell>
                        </TableRow>
                      </TableHead>
                      <TableBody>
                        {students.map(student => (
                          <TableRow key={student.id}>
                            <TableCell padding='checkbox'>
                              <Checkbox />
                            </TableCell>
                            <TableCell>{student.id}</TableCell>
                            <TableCell>{student.studentID}</TableCell>
                            <TableCell>{student.name}</TableCell>
                            <TableCell>{student.password}</TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </TableContainer>
                </Paper>
              </Container>
            </section>
          </Grid>


          {/* INSTRUCTOR LIST */}
          <Grid item xs={12}>
            <section>
              <Container>
                <Paper elevation={7}>
                  <TableContainer>
                    <Container>
                      <Typography className={classes.title} variant='h4'>
                        Instructor List
                      </Typography>
                    </Container>
                    <Toolbar>
                      <div className={classes.searchIcon}>
                        <Search />
                      </div>
                      <InputBase
                        placeholder="Search…"
                        classes={{
                          root: classes.inputRoot,
                          input: classes.inputInput,
                        }}
                        inputProps={{ 'aria-label': 'search' }}
                      />
                    </Toolbar>
                    <Table>
                      <TableHead className={classes.tableHead}>
                        <TableRow>
                          <TableCell padding='checkbox'>
                            <Checkbox />
                          </TableCell>
                          <TableCell>ID</TableCell>
                          <TableCell>Name</TableCell>
                        </TableRow>
                      </TableHead>
                      <TableBody>
                        {instructors.map(instructor => (
                          <TableRow key={instructor.id}>
                            <TableCell padding='checkbox'>
                              <Checkbox />
                            </TableCell>
                            <TableCell>{instructor.id}</TableCell>
                            <TableCell>{instructor.name}</TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </TableContainer>
                </Paper>
              </Container>
            </section>
          </Grid>


          {/* CLASSROOM LIST */}
          <Grid item xs={12}>
            <section>
              <Container>
                <Paper elevation={7}>
                  <TableContainer>
                    <Container>
                      <Typography className={classes.title} variant='h4'>
                        Classroom List
                      </Typography>
                    </Container>
                    <Toolbar>
                      <div className={classes.searchIcon}>
                        <Search />
                      </div>
                      <InputBase
                        placeholder="Search…"
                        classes={{
                          root: classes.inputRoot,
                          input: classes.inputInput,
                        }}
                        inputProps={{ 'aria-label': 'search' }}
                      />
                    </Toolbar>
                    <Table>
                      <TableHead className={classes.tableHead}>
                        <TableRow>
                          <TableCell padding='checkbox'>
                            <Checkbox />
                          </TableCell>
                          <TableCell>ID</TableCell>
                          <TableCell>Subject Title</TableCell>
                          <TableCell>Instructor</TableCell>
                          <TableCell>Section</TableCell>
                        </TableRow>
                      </TableHead>
                      <TableBody>
                        {classrooms.map(classroom => (
                          <TableRow key={classroom.id}>
                            <TableCell padding='checkbox'>
                              <Checkbox />
                            </TableCell>
                            <TableCell>{classroom.id}</TableCell>
                            <TableCell>{classroom.subjectName}</TableCell>
                            <TableCell>{classroom.instructor}</TableCell>
                            <TableCell>{classroom.yearSection}</TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </TableContainer>
                </Paper>
              </Container>
            </section>
          </Grid>

        </Grid>
      </Container>
    </>
  )
}
